content:
{
  "sentences": [
    {
      "text": "我明天要跟朋友一起去喝咖啡。",
      "pinyin": "Wǒ míngtiān yào gēn péngyou yīqǐ qù hē kāfēi.",
      "pinyin_numeric": "wo3 ming2tian1 yao4 gen1 peng2you3 yi4qi3 qu4 he1 ka1fei1",
      "translation_en": "I'm going to drink coffee with a friend tomorrow.",
      "translation_ko": "저는 내일 친구와 함께 커피를 마시러 갈 거예요."
    },
    {
      "text": "我們要約在咖啡店見面嗎？",
      "pinyin": "Wǒmen yào yuē zài kāfēidiàn jiànmiàn ma?",
      "pinyin_numeric": "wo3men yao4 yue1 zai4 ka1fei1dian4 jian4mian4 ma0",
      "translation_en": "Are we going to meet at the coffee shop?",
      "translation_ko": "우리 커피숍에서 만나기로 할까요?"
    },
    {
      "text": "他打算下個星期要跟我一起看電影。",
      "pinyin": "Tā dǎsuàn xià ge xīngqī yào gēn wǒ yīqǐ kàn diànyǐng.",
      "pinyin_numeric": "ta1 da3suan4 xia4 ge4 xing1qi1 yao4 gen1 wo3 yi4qi3 kan4 dian4ying3",
      "translation_en": "He plans to watch a movie with me next week.",
      "translation_ko": "그는 다음 주에 저와 함께 영화를 보려고 해요."
    },
    {
      "text": "我們要約幾點在餐廳門口碰面？",
      "pinyin": "Wǒmen yào yuē jǐ diǎn zài cāntīng ménkǒu pèngmiàn?",
      "pinyin_numeric": "wo3men yao4 yue1 ji3 dian3 zai4 can1ting1 men2kou3 peng4mian4",
      "translation_en": "What time are we going to meet at the restaurant entrance?",
      "translation_ko": "몇 시에 식당 입구에서 만나기로 할까요?"
    },
    {
      "text": "我明天要跟朋友一起去逛街。",
      "pinyin": "Wǒ míngtiān yào gēn péngyou yīqǐ qù guàngjiē.",
      "pinyin_numeric": "wo3 ming2tian1 yao4 gen1 peng2you3 yi4qi3 qu4 guang4jie1",
      "translation_en": "I'm going shopping with a friend tomorrow.",
      "translation_ko": "저는 내일 친구와 함께 쇼핑하러 갈 거예요."
    },
    {
      "text": "她想要改時間，因為她最近很忙。",
      "pinyin": "Tā xiǎng yào gǎi shíjiān, yīnwèi tā zuìjìn hěn máng.",
      "pinyin_numeric": "ta1 xiang3 yao4 gai3 shi2jian1, yin1wei4 ta1 zui4jin4 hen3 mang2",
      "translation_en": "She wants to change the time because she's been very busy lately.",
      "translation_ko": "그녀는 시간을 바꾸고 싶어 해요. 왜냐하면 그녀가 요즘 매우 바쁘거든요."
    },
    {
      "text": "我們要約在電影院前面等。",
      "pinyin": "Wǒmen yào yuē zài diànyǐngyuàn qiánmiàn děng.",
      "pinyin_numeric": "wo3men yao4 yue1 zai4 dian4ying3yuan4 qian2mian4 deng3",
      "translation_en": "We're going to meet and wait in front of the movie theater.",
      "translation_ko": "우리는 영화관 앞에서 만나서 기다리기로 할 거예요."
    },
    {
      "text": "你明天要跟我一起去吃飯嗎？",
      "pinyin": "Nǐ míngtiān yào gēn wǒ yīqǐ qù chīfàn ma?",
      "pinyin_numeric": "ni3 ming2tian1 yao4 gen1 wo3 yi4qi3 qu4 chi1fan4 ma0",
      "translation_en": "Are you going to eat with me tomorrow?",
      "translation_ko": "내일 저와 함께 밥 먹으러 갈래요?"
    },
    {
      "text": "我們要約好時間，然後再聯絡。",
      "pinyin": "Wǒmen yào yuē hǎo shíjiān, ránhòu zài liánluò.",
      "pinyin_numeric": "wo3men yao4 yue1 hao3 shi2jian1, ran2hou4 zai4 lian2luo4",
      "translation_en": "We're going to set a time and then get in touch again.",
      "translation_ko": "우리는 시간을 정한 다음에 다시 연락할 거예요."
    },
    {
      "text": "他打算要取消今天的約會。",
      "pinyin": "Tā dǎsuàn yào qǔxiāo jīntiān de yuēhuì.",
      "pinyin_numeric": "ta1 da3suan4 yao4 qu3xiao1 jin1tian1 de5 yue1hui4",
      "translation_en": "He plans to cancel today's date.",
      "translation_ko": "그는 오늘 약속을 취소하려고 해요."
    }
  ]
}
